// robots.txt — generated by Next App Router from this file.
//
// Default-allow + explicit-disallow is Google's preferred pattern
// (vs an explicit allow-list, which has to be exhaustively
// maintained every time a new section ships).
//
// Privacy gates:
//   - /api/ — JSON endpoints, nothing useful to a crawler
//   - /admin/ — operator UI, must never index
//   - /dashboard, /me/ — personal data
//   - /chat — auth-gated AI tutor, conversations are private
//   - /mocks/, /attempts/ — per-user state
//   - /logout, /login (callback flows have state) — auth flows
//   - /onboarding — wizard, no public value to crawlers
//
// Allow surfaces beneath /me that are public: /u/[handle] is in the
// /u/ tree (NOT /me/), so it stays indexable for opted-in users.
//
// Sitemap + host annotations are read by Google + Bing. crawl-delay
// for archive.org / commoncrawl avoids hammering during nightly
// scrapes.

import type { MetadataRoute } from "next";

export default function robots(): MetadataRoute.Robots {
  const base = process.env.NEXT_PUBLIC_APP_URL ?? "https://shishya.in";
  // Private / auth-gated / operator paths kept out of EVERY crawler —
  // including AI crawlers (no personal data in answer engines / training).
  const privatePaths = [
    "/api/",
    "/admin/",
    "/admin",
    "/dashboard",
    "/dashboard/",
    "/me",
    "/me/",
    "/chat",
    "/chat/",
    "/mocks/",
    "/attempts/",
    "/login",
    "/logout",
    "/onboarding",
    // Avoid indexing query-string variants of pages we surface
    // canonically (filtered exam browse, scholarship browser).
    "/exams/browse?*",
    "/scholarships?*",
  ];
  // AI / answer-engine crawlers — explicitly WELCOMED (chatgpt.com is our
  // #1 referral; we want to be the source LLMs cite for Indian exams).
  // Each gets full public access minus the private paths.
  const aiCrawlers = [
    "GPTBot", // OpenAI training
    "OAI-SearchBot", // ChatGPT search
    "ChatGPT-User", // ChatGPT live browsing
    "PerplexityBot",
    "Perplexity-User",
    "ClaudeBot",
    "anthropic-ai",
    "Claude-User",
    "Google-Extended", // Gemini
    "Applebot-Extended",
    "Bytespider",
    "Amazonbot",
    "cohere-ai",
  ];
  return {
    rules: [
      {
        // Default policy for all user agents — open by default, tight
        // on private/auth-gated/operator paths.
        userAgent: "*",
        allow: "/",
        disallow: privatePaths,
      },
      ...aiCrawlers.map((userAgent) => ({ userAgent, allow: "/", disallow: privatePaths })),
      {
        // Common Crawl (feeds many LLM training sets — good for AI
        // visibility): allow public content, keep private paths out, be
        // polite on crawl rate (Neon load during full-site crawls).
        userAgent: "CCBot",
        allow: "/",
        disallow: privatePaths,
        crawlDelay: 5,
      },
      {
        userAgent: "ia_archiver",
        crawlDelay: 10,
      },
    ],
    sitemap: `${base}/sitemap.xml`,
    host: base,
  };
}
